import React from "react"

const BundleCard = ({ bundle, deals }) => {
  const getCheapestDeal = (dealIds) => {
    const matched = dealIds
      .map(id => deals.find(d => d.id === id))
      .filter(Boolean)
    if (!matched.length) return null
    return matched.sort((a, b) => {
      const pa = a.price.monthly || a.price.annual || (a.price.monthlyPerGB ? a.price.monthlyPerGB * 100 : 9999)
      const pb = b.price.monthly || b.price.annual || (b.price.monthlyPerGB ? b.price.monthlyPerGB * 100 : 9999)
      return pa - pb
    })[0]
  }

  const categoryColors = {
    "ai-infra": "#8b5cf6",
    "web-infra": "#10b981",
  }

  return (
    <article style={cardStyle}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "0.5rem" }}>
        <span style={{ fontSize: "2rem" }}>{bundle.icon}</span>
        <span style={{
          fontSize: "0.7rem",
          padding: "0.2rem 0.6rem",
          borderRadius: 12,
          background: categoryColors[bundle.category] || "#444",
          color: "#fff",
          fontWeight: 600,
          textTransform: "uppercase",
        }}>
          {bundle.category.replace("-", " ")}
        </span>
      </div>
      <h3 style={{ margin: "0.3rem 0", color: "#e0e0e0", fontSize: "1.15rem" }}>{bundle.name}</h3>
      <p style={{ margin: "0.4rem 0 1rem", color: "#888", fontSize: "0.85rem", lineHeight: 1.5 }}>{bundle.description}</p>
      
      <div style={{ marginBottom: "1rem" }}>
        {bundle.resources.map((r, i) => {
          const cheapest = getCheapestDeal(r.dealIds)
          return (
            <div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "0.3rem 0", borderBottom: "1px solid #1a1a1a", fontSize: "0.82rem" }}>
              <span style={{ color: "#aaa" }}>{r.label} {r.required ? "" : "(optional)"}</span>
              <span style={{ color: cheapest ? "#10b981" : "#666", fontWeight: 600 }}>
                {cheapest ? formatPrice(cheapest) : "—"}
              </span>
            </div>
          )
        })}
      </div>

      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <span style={{ fontSize: "0.75rem", color: "#666" }}>
          {bundle.estimatedCostRange.period === "annual" ? "/year" : "/month"}
        </span>
        <span style={{ color: "#10b981", fontWeight: 700, fontSize: "1.1rem" }}>
          ${bundle.estimatedCostRange.min}–${bundle.estimatedCostRange.max}
        </span>
      </div>
      
      <div style={{ marginTop: "0.5rem", fontSize: "0.7rem", color: "#555" }}>
        {bundle.setupSteps.length} setup steps · {bundle.difficulty}
      </div>
    </article>
  )
}

function formatPrice(deal) {
  if (deal.price.monthly) return `$${deal.price.monthly}/mo`
  if (deal.price.annual) return `$${deal.price.annual}/yr`
  if (deal.price.monthlyPerGB) return `$${deal.price.monthlyPerGB}/GB`
  if (deal.price.hourly) return `$${deal.price.hourly}/hr`
  if (deal.price.inputPer1M) return `$${deal.price.inputPer1M}/1M tok`
  return "See site"
}

const cardStyle = {
  background: "#111",
  border: "1px solid #222",
  borderRadius: 12,
  padding: "1.5rem",
  transition: "border-color 0.2s, transform 0.2s",
  cursor: "pointer",
}

export default BundleCard
export { formatPrice }
